package sched

import (
	"fmt"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// Config tunes the active-backup scheduler.
type Config struct {
	// FailbackAfter is the failback hysteresis dwell: once a higher-priority
	// path recovers (returns to StateUp) while egress is on a lower-priority
	// backup, the scheduler holds on the backup until the higher-priority path
	// has stayed continuously Up for at least this long before failing egress
	// BACK to it. This is the anti-thrash guard: a primary that flaps up/down
	// never repeatedly steals egress back, because each dip restarts the dwell.
	//
	// Failover in the OTHER direction (active path going Down) is never delayed:
	// the scheduler switches to the best remaining path immediately, since a dead
	// active path cannot carry traffic while a timer runs. The asymmetry — instant
	// failover, debounced failback — is what makes recovery non-thrashing.
	FailbackAfter time.Duration
}

// ActiveBackup is the P1 send-side scheduler: a single ACTIVE path (the
// highest-priority eligible one — index 0, the preferred primary, when it is
// up) carries ALL egress; every other path stays idle (data-thrift by
// construction). It reads per-path liveness from the injected T13 PathHealth
// sources and a clock for the failback dwell, so it is deterministic under test.
//
// Priority is the health-slice order: index 0 is the preferred primary, higher
// indices are progressively-lower-priority backups. A path is eligible when its
// PathHealth reports StateUp.
//
// Concurrency: the send path is concurrent, so Pick recomputes the active path
// under s.mu and every field it touches is guarded by that mutex. It never calls
// back into the Bind, so a Bind holding its own send lock across Pick cannot
// deadlock against it.
type ActiveBackup struct {
	health []PathHealth // index = priority; [0] is the preferred primary
	clock  telemetry.Clock
	cfg    Config
	log    log.Logger

	mu           sync.Mutex
	active       int       // cached selection; -1 == no eligible path
	pending      int       // failback candidate index; -1 == none pending
	pendingSince time.Time // when the current failback candidate first became eligible
}

// compile-time proof ActiveBackup is a (dynamic) Scheduler.
var (
	_ Scheduler        = (*ActiveBackup)(nil)
	_ DynamicScheduler = (*ActiveBackup)(nil)
)

// NewActiveBackup builds the active-backup scheduler over health (priority
// order, index 0 = preferred primary). It fails fast on an empty health set or a
// nil dependency: the scheduler is a required, fully-wired collaborator, not an
// optional one.
func NewActiveBackup(health []PathHealth, cfg Config, clock telemetry.Clock, logger log.Logger) (*ActiveBackup, error) {
	if len(health) == 0 {
		return nil, fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return nil, fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	if clock == nil {
		return nil, fmt.Errorf("sched: clock is required")
	}
	if logger == nil {
		return nil, fmt.Errorf("sched: logger is required")
	}
	return &ActiveBackup{
		health:  health,
		clock:   clock,
		cfg:     cfg,
		log:     logger.Component("sched"),
		active:  -1,
		pending: -1,
	}, nil
}

// AddPath admits h as a new lowest-priority path and returns its index (the new
// tail). Appending at the tail leaves every existing index — including the cached
// active/pending — unchanged, and the new path can only become active once every
// higher-priority path is down, so a runtime admission never disturbs the active
// selection of the surviving paths (T30). It is safe for concurrent callers.
func (s *ActiveBackup) AddPath(h PathHealth) (int, error) {
	if h == nil {
		return 0, fmt.Errorf("sched: cannot add a nil path health source")
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append(s.health, h)
	return len(s.health) - 1, nil
}

// RemovePath drops the health source at index i and repairs the cached selection
// so the surviving paths are undisturbed (T30). The active/pending indices are
// remapped by IDENTITY rather than by arithmetic: the survivor a cached index
// pointed at keeps being pointed at after the slice compaction, and a cached
// index that pointed at the removed path is cleared (-1). Clearing active makes
// the next Pick fail egress over to the best remaining path; clearing pending
// abandons an in-flight failback dwell whose candidate no longer exists. It is
// safe for concurrent callers.
func (s *ActiveBackup) RemovePath(i int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if i < 0 || i >= len(s.health) {
		return fmt.Errorf("sched: remove path index %d out of range [0,%d)", i, len(s.health))
	}
	// Capture the identities the cached indices point at BEFORE compaction, unless
	// they point at the path being removed (then they are cleared).
	var activeH, pendingH PathHealth
	if s.active >= 0 && s.active != i {
		activeH = s.health[s.active]
	}
	if s.pending >= 0 && s.pending != i {
		pendingH = s.health[s.pending]
	}
	s.health = append(s.health[:i], s.health[i+1:]...)
	s.active = indexOfHealth(s.health, activeH)
	s.pending = indexOfHealth(s.health, pendingH)
	if s.pending < 0 {
		s.pendingSince = time.Time{}
	}
	return nil
}

// SetPaths replaces the entire health list with a defensive copy of health and
// clears the cached selection (active/pending), so the next Pick re-derives the
// active path from live liveness. The Bind calls it on every Open to re-align the
// scheduler's membership with the freshly-rebuilt path slice, which is what makes a
// runtime path add/remove survive a Close→Open cycle index-aligned (T30). It fails
// fast on an empty set or a nil element, matching NewActiveBackup's contract. It is
// safe for concurrent callers.
func (s *ActiveBackup) SetPaths(health []PathHealth) error {
	if len(health) == 0 {
		return fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append([]PathHealth(nil), health...)
	s.active = -1
	s.pending = -1
	s.pendingSince = time.Time{}
	return nil
}

// indexOfHealth returns the index of h in hs by identity, or -1 when h is nil or
// absent. Interface equality is pointer identity for the concrete *Prober /
// health values the scheduler holds.
func indexOfHealth(hs []PathHealth, h PathHealth) int {
	if h == nil {
		return -1
	}
	for i := range hs {
		if hs[i] == h {
			return i
		}
	}
	return -1
}

// Pick returns the index of the current active path, recomputing the selection
// against live path health and the clock. It is safe for concurrent callers.
// class is ignored: active-backup has no pacer, so every frame class is treated
// identically (defect D22's control-frame exemption is a pacing concern).
func (s *ActiveBackup) Pick(_ FrameClass) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(s.clock.Now())
	return s.active
}

// Recompute re-derives the active path from current liveness and the failback
// dwell, exactly as Pick does, but discards the result. Active-backup's selection
// is a single cached index recomputed purely from liveness and the clock, so Pick
// is idempotent and Recompute IS Pick-without-the-return: the eager-failover nudge
// (defect D18/T40) can drive an egress-lull failover recompute through it with no
// behavioural difference from the old Pick-based nudge. It is safe for concurrent
// callers.
func (s *ActiveBackup) Recompute() {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(s.clock.Now())
}

// recomputeLocked re-derives the active path from current liveness and the
// failback dwell. Caller holds s.mu.
//
// Selection rule, in priority order:
//   - best = the lowest-index (highest-priority) path currently StateUp.
//   - No path up -> no active path.
//   - Cold start, or the current active is no longer up (best is a
//     lower-priority path) -> switch immediately (instant failover).
//   - best already IS the active -> stable, nothing to do.
//   - best is a HIGHER-priority path than the active (the primary recovered)
//     -> a failback candidate: hold on the current active until best has been
//     continuously up for FailbackAfter, THEN fail back. If the current active
//     itself goes down mid-dwell, move to best at once rather than stall.
func (s *ActiveBackup) recomputeLocked(now time.Time) {
	best := s.bestEligibleLocked()

	if best < 0 {
		s.pending = -1
		s.setActiveLocked(-1, "no eligible path")
		return
	}
	if s.active < 0 || best > s.active {
		// Cold start, or the active path is no longer eligible (best, the first
		// eligible index, sits below it) -> immediate (fail)over.
		s.pending = -1
		s.setActiveLocked(best, "failover")
		return
	}
	if best == s.active {
		s.pending = -1
		return
	}

	// best < s.active: a higher-priority path recovered -> debounced failback.
	if s.pending != best {
		s.pending = best
		s.pendingSince = now
	}
	if now.Sub(s.pendingSince) >= s.cfg.FailbackAfter {
		s.pending = -1
		s.setActiveLocked(best, "failback")
		return
	}
	// Still within the dwell: keep the current active while it stays eligible; if
	// it has gone down, we cannot stall on it — move to best now.
	if s.health[s.active].State() != telemetry.StateUp {
		s.pending = -1
		s.setActiveLocked(best, "failover during failback dwell")
	}
}

// bestEligibleLocked returns the lowest-index path reporting StateUp, or -1.
func (s *ActiveBackup) bestEligibleLocked() int {
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			return i
		}
	}
	return -1
}

// setActiveLocked stores the active index and logs a transition only when it
// actually changes, so a saturated send path does not log on every Pick.
func (s *ActiveBackup) setActiveLocked(idx int, reason string) {
	if s.active == idx {
		return
	}
	from := s.active
	s.active = idx
	s.log.Info("scheduler active path change",
		"from", from,
		"to", idx,
		"reason", reason,
	)
}

package sched

import (
	"github.com/7mind/wanbond/internal/telemetry"
)

// Negative Pick sentinels. Pick returns a NON-NEGATIVE path index when a datagram
// should egress, and one of these when it should not. They are distinct so the Send
// path can tell a genuine outage (no eligible path) apart from a transient pacer
// shedding a frame while every path is healthy — the two must not read the same in
// operator logs or the e2e log-grep harness.
const (
	// PickNone means no path is currently eligible (a total outage among this
	// scheduler's paths). The Bind maps it to "no healthy path".
	PickNone = -1
	// PickPaced means eligible paths EXIST but every one is momentarily paced out, so
	// this frame is shed (dropped) to bound egress and the send backlog. The paths are
	// healthy — this is deliberate rate limiting, NOT an outage. Only a pacing-enabled
	// weighted scheduler ever returns it.
	PickPaced = -2
)

// FrameClass tags an outbound datagram with the traffic class the pacer must treat
// it as (defect D22). The multipath Bind classifies each frame from the inner
// WireGuard message type and passes the class to Pick so a pacing scheduler can give
// WireGuard control frames (handshake init/response, cookie reply, keepalive) a
// different admission policy than bulk data. Pick() has no other frame-type
// visibility, so this is the ONLY channel by which frame-type reaches the pacer.
type FrameClass uint8

const (
	// ClassData is bulk/opaque data (a WireGuard transport datagram carrying tunnelled
	// payload). It is fully paced: under a weighted scheduler with pacing enabled it is
	// subject to the per-path token buckets and is shed (PickPaced) when they are empty.
	ClassData FrameClass = iota
	// ClassControl is a WireGuard control frame — handshake initiation/response, cookie
	// reply, or keepalive. It is pacing-EXEMPT: a pacing scheduler never sheds it for an
	// empty token bucket and never spends a data token for it, so sustained bulk overload
	// cannot starve rekey (defect D22). Control frames originate from OUR OWN WireGuard
	// engine on the send path (an attacker cannot inject them here), and WireGuard's own
	// state machine bounds their rate, so exempting them from the data pace is safe.
	ClassControl
)

// Scheduler is the send-side path-selection policy the multipath Bind consults
// for every outbound datagram. It is the extension seam for the send scheduler:
// active-backup failover (ActiveBackup, the P1 MVP) is one implementation; the
// later weighted / FEC-aware policy (T21) is a DIFFERENT implementation of this
// same interface, swapped in at the composition root with no Bind change.
type Scheduler interface {
	// Pick returns the index of the path the next datagram must egress on, in
	// the path priority order the scheduler was built over (index 0 = preferred
	// primary). It returns a negative value when no datagram should be sent this
	// call; the negative value is one of the Pick* sentinels (PickNone for no
	// eligible path, PickPaced for a healthy-but-paced-out shed), so the caller can
	// tell a genuine outage apart from deliberate rate limiting. Pick is safe for
	// concurrent callers on the Bind's send path.
	//
	// class is the frame's traffic class (defect D22): a pacing scheduler exempts
	// ClassControl (WireGuard handshake/keepalive) from the data token buckets so
	// bulk overload cannot shed control frames and starve rekey, while ClassData is
	// fully paced. A non-pacing scheduler (active-backup) ignores class.
	//
	// Pick MAY be stateful: a weighted/aggregating scheduler advances its
	// distribution bookkeeping (deficit/round-robin credits, pacing tokens, offered-
	// load meter) on every call, so ONE Pick consumes ONE frame-selection slot.
	// Callers that only want the liveness-derived active set refreshed — without
	// perturbing distribution — MUST call Recompute, not Pick (see the T40 eager-
	// failover nudge in the multipath Bind).
	Pick(class FrameClass) int

	// Recompute refreshes the scheduler's liveness-derived selection state (which
	// paths are eligible, which is the active primary) from the current PathHealth,
	// and logs any active-path transition, WITHOUT selecting or consuming a frame
	// slot: it advances no distribution/pacing/load state. It is the split-out
	// "recompute the eligible/active set from liveness" half of the old Pick, so the
	// eager-failover nudge (defect D18/T40) can drive an egress-lull failover recompute
	// without stealing a weighted-distribution slot the way a spurious Pick would. For
	// an idempotent scheduler (active-backup) it is exactly Pick without the return;
	// for a stateful one (weighted) it is strictly the non-consuming subset. It is
	// safe for concurrent callers and never calls back into the Bind.
	Recompute()
}

// PathQuality is the per-path measured-quality source the weighted scheduler reads
// to derive distribution weights: the read side of the T13 telemetry Estimate
// (RTT/Jitter/Loss), ANALOGOUS to PathHealth but exposing the quality snapshot
// rather than the up/down verdict. *telemetry.Prober satisfies BOTH PathHealth and
// PathQuality (its Estimate() is mutex-guarded, so it meets the same concurrency
// contract PathHealth documents), which is how one *Prober per path feeds liveness
// AND weight to the scheduler. The weighted scheduler's unit tests drive a synthetic
// PathQuality so the RTT/loss → weight formula is exercised on hand-built Estimates
// with no real probe stream.
type PathQuality interface {
	Estimate() telemetry.Estimate
}

// DynamicScheduler is a Scheduler whose path set can change at runtime (T30): a
// path may be admitted or dropped WITHOUT rebuilding the scheduler or disturbing
// the active selection of the surviving paths. The multipath Bind holds its
// scheduler as a plain Scheduler and type-asserts to this richer interface only
// when a runtime path add/remove is requested, so the Scheduler seam (and the
// T21 weighted policy that will implement it) is preserved: a scheduler that
// does not support dynamic membership simply cannot back a reloadable bind.
//
// The index space is the SAME priority-ordered index Pick returns, and the Bind
// keeps its own path slice index-aligned with this scheduler's path list, so an
// index returned by Pick always addresses the matching path. Both methods are
// safe for concurrent callers.
type DynamicScheduler interface {
	Scheduler
	// AddPath admits h as a NEW lowest-priority path (highest index) and returns
	// that index. Appending at the tail cannot change any existing path's index
	// nor steal the active selection from a higher-priority survivor: an
	// active-backup policy only ever selects the new path once every
	// higher-priority path is down. h must be non-nil.
	AddPath(h PathHealth) (int, error)
	// RemovePath drops the path at index i (shifting higher indices down by one)
	// and repairs the cached selection so a surviving path keeps being selected
	// and, if the dropped path was the active one, egress fails over to the best
	// remaining path on the next Pick. i must be in range.
	RemovePath(i int) error
	// SetPaths replaces the ENTIRE path/health list with health (priority order,
	// index 0 = preferred primary) and clears any cached selection, so the next
	// Pick re-derives the active path from live liveness. The Bind calls it on
	// every Open to re-align the scheduler's membership with the path slice it
	// rebuilds from the current definitions — the single reconciliation point that
	// makes a runtime path add/remove survive a Close→Open cycle index-aligned
	// (T30). It is safe for concurrent callers; health must be non-empty and hold
	// no nil element.
	SetPaths(health []PathHealth) error
}

// PathHealth is the per-path liveness the scheduler consumes: the read side of
// the T13 telemetry liveness state machine, so the scheduler reads exactly the
// up/down verdict T13 already computes (with its own probe-loss hysteresis)
// rather than duplicating detection here.
//
// Concurrency contract: Pick runs on the Bind send path CONCURRENTLY with the
// probe/timer goroutines that mutate liveness, so a production PathHealth MUST
// be INTERNALLY SYNCHRONIZED. *telemetry.Prober satisfies this — its State()
// takes the Prober's mutex (probe.go). A bare *telemetry.Liveness does NOT: it
// is not independently synchronized (probe.go: "must be reached only through
// the Prober") and its State() is an unguarded field read (liveness.go), so
// wiring a live, probe-driven *Liveness directly here is a data race — use a
// *Prober or an explicitly-locked adapter instead. (The sched unit tests drive
// a raw *Liveness on a single goroutine with no concurrent writer, which is not
// a race and is fine for testing.)
type PathHealth interface {
	State() telemetry.PathState
}

// AlwaysUp is a PathHealth that reports StateUp unconditionally. It is the
// composition-root placeholder used until the probe-transport wiring (a
// follow-up task) drives real per-path *telemetry.Prober liveness: with every
// path statically Up, the active-backup scheduler keeps all egress on the
// preferred primary (the data-thrift bring-up behaviour), and swapping in real
// Probers later activates failover with no further Bind or scheduler change.
type AlwaysUp struct{}

// State reports the path as up.
func (AlwaysUp) State() telemetry.PathState { return telemetry.StateUp }

package sched

import (
	"fmt"
	"math"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// WeightedConfig tunes the weighted-aggregation scheduler. The device builds it
// from config.SchedulerConfig; sched holds its own struct so the package does not
// depend on config. Every field is validated by NewWeighted (fail-fast at the
// composition root), mirroring the config-boundary validation.
type WeightedConfig struct {
	// PerPathCapacity is the reference per-path capacity in frame-selection slots per
	// second: the denominator the aggregation load-gate compares offered load against,
	// and (when Pacing is on) the per-path token-bucket refill rate. There is no
	// measured BDP (P0 §7), so capacity is expressed in the only unit the scheduler
	// observes — Pick() invocations per second. Must be > 0.
	PerPathCapacity float64
	// EngageFraction engages aggregation once smoothed offered load exceeds
	// EngageFraction*PerPathCapacity. In (0,1].
	EngageFraction float64
	// DisengageFraction collapses aggregation to primary-only once smoothed offered
	// load stays below DisengageFraction*PerPathCapacity for CollapseDwell. In
	// [0,EngageFraction): the gap is the hysteresis band that keeps the metered path
	// from dribbling on/off around a single threshold (data-thrift, requirement 2).
	DisengageFraction float64
	// CollapseDwell is the sustained-low-load dwell before collapsing to primary-only
	// (the temporal half of the hysteresis, mirroring the active-backup failback dwell).
	CollapseDwell time.Duration
	// LoadTau is the time constant of the exponentially-weighted offered-load rate
	// estimator. Must be > 0.
	LoadTau time.Duration

	// Pacing turns per-path send-pacing on. When false the token buckets are bypassed
	// (a documented no-op: P0 §7 could not empirically size the pace in the unmetered
	// fixture), but PerPathCapacity still drives the aggregation gate.
	Pacing bool
	// PacingBurst is the per-path token-bucket burst in frame slots. Must be > 0 when
	// Pacing is on.
	PacingBurst float64

	// WeightRTTFloor floors RTT in the weight formula so a cold path (no RTT samples
	// yet, near-zero RTT) cannot be handed unbounded weight. Must be > 0.
	WeightRTTFloor time.Duration
	// WeightLossFloor floors the loss term under the square root so a zero-loss path
	// gets a large-but-finite weight and two zero-loss paths split by inverse-RTT
	// alone. Must be > 0.
	WeightLossFloor float64
}

func (c WeightedConfig) validate() error {
	if c.PerPathCapacity <= 0 {
		return fmt.Errorf("sched: weighted PerPathCapacity must be > 0, got %g", c.PerPathCapacity)
	}
	if c.EngageFraction <= 0 || c.EngageFraction > 1 {
		return fmt.Errorf("sched: weighted EngageFraction must be in (0,1], got %g", c.EngageFraction)
	}
	if c.DisengageFraction < 0 || c.DisengageFraction >= c.EngageFraction {
		return fmt.Errorf("sched: weighted DisengageFraction must be in [0,EngageFraction=%g), got %g", c.EngageFraction, c.DisengageFraction)
	}
	if c.CollapseDwell < 0 {
		return fmt.Errorf("sched: weighted CollapseDwell must be >= 0, got %s", c.CollapseDwell)
	}
	if c.LoadTau <= 0 {
		return fmt.Errorf("sched: weighted LoadTau must be > 0, got %s", c.LoadTau)
	}
	if c.Pacing && c.PacingBurst <= 0 {
		return fmt.Errorf("sched: weighted PacingBurst must be > 0 when pacing is enabled, got %g", c.PacingBurst)
	}
	if c.WeightRTTFloor <= 0 {
		return fmt.Errorf("sched: weighted WeightRTTFloor must be > 0, got %s", c.WeightRTTFloor)
	}
	if c.WeightLossFloor <= 0 {
		return fmt.Errorf("sched: weighted WeightLossFloor must be > 0, got %g", c.WeightLossFloor)
	}
	return nil
}

// FECPolicy is the P3+ forward-error-correction extension seam. Given the path a
// frame was scheduled onto and the current eligible set, it returns ADDITIONAL path
// indices the frame should ALSO egress on for redundancy (e.g. a repair copy on a
// second path). This is a documented hook, NOT an implementation: the current
// single-path Scheduler.Pick returns one index, so wiring redundant transmission
// requires the P3 Bind change that fans a frame out to several sockets. Until then
// a nil policy adds no redundancy and RedundantPaths returns nothing, so the seam is
// inert but present and unit-tested.
type FECPolicy interface {
	RedundantPaths(chosen int, eligible []int) []int
}

// WeightedScheduler is the T21 send-side scheduler: a weighted-aggregation policy
// that, under load, stripes a single flow across every eligible path in proportion
// to a per-path RTT/loss-derived weight, and at low load COLLAPSES to the primary
// (index 0) so the metered backup path stays ~idle (data-thrift, requirement 2). It
// engages the backup only once offered load exceeds one path's capacity and
// disengages with hysteresis (a two-threshold band plus a collapse dwell) so the
// metered path never dribbles on/off. Per-path send-pacing (token buckets) bounds
// each path's egress rate so aggregation does not build a standing queue that
// inflates latency-under-load (P0 §7); pacing is a config no-op when disabled.
//
// It reads per-path liveness from PathHealth (the T13 up/down verdict) and per-path
// quality from PathQuality (the T13 Estimate: RTT/loss). In production BOTH are the
// SAME *telemetry.Prober per path; the unit tests drive synthetic sources.
//
// Weight formula (Mathis-style throughput proxy). A single steady-state TCP flow's
// bandwidth is ∝ 1/(RTT·√p) (Mathis et al.); used here as a RELATIVE path-quality
// proxy it directs more of the aggregate flow onto the path a flow would run faster
// on. Per eligible path:
//
//	w_i = 1 / ( max(RTT_i, RTTFloor) · sqrt(Loss_i + LossFloor) )
//
// normalized over the eligible set. RTTFloor bounds a cold/zero-RTT path; LossFloor
// keeps a zero-loss path finite (two zero-loss paths then split by inverse-RTT
// alone). There is no measured bandwidth to use (Estimate is RTT/Jitter/Loss only,
// P0 §7), so an RTT/loss proxy is the honest choice.
//
// Concurrency mirrors ActiveBackup: every field is guarded by s.mu; the send path
// recomputes under the lock and never calls back into the Bind, so a Bind holding
// its own send lock across Pick cannot deadlock.
//
// Statefulness and the T40 nudge. Pick is STATEFUL — it advances the offered-load
// meter, the aggregation gate, the pacing buckets, and the smooth-weighted-round-
// robin credits, so ONE Pick == ONE frame. The eager-failover nudge (defect D18)
// must therefore NOT call Pick (it would steal a distribution slot and skew the
// weights); it calls Recompute, which refreshes only the liveness-derived eligible/
// active set and logs any active-path transition, touching NONE of that per-frame
// distribution state.
type WeightedScheduler struct {
	health  []PathHealth  // index = priority; [0] is the preferred primary
	quality []PathQuality // parallel to health; element may be nil (neutral weight)
	clock   telemetry.Clock
	cfg     WeightedConfig
	log     log.Logger
	fec     FECPolicy // P3+ redundancy seam; nil = no FEC

	mu sync.Mutex

	// Offered-load meter: an exponentially-weighted event-rate estimator (each Pick is
	// one event; the estimate converges to the offered Pick rate in events/sec).
	loadRate float64
	haveLoad bool
	lastLoad time.Time

	// Aggregation gate (hysteresis).
	aggregating bool
	belowSince  time.Time // when load first fell below the disengage threshold; zero == not pending

	// Smooth-weighted-round-robin credits, parallel to health (global path index).
	current []float64

	// Per-path pacing token buckets, parallel to health.
	tokens   []float64
	lastFill time.Time
	haveFill bool

	// Active-primary cache: the best eligible path, for eager-failover transition
	// logging (parity with ActiveBackup). -1 == none.
	active int

	// Pacer-shedding log rate limiter: under sustained overload shedding is per-frame
	// (thousands/s), so the "pacer shedding" diagnostic is coalesced to at most one
	// record per shedLogInterval, carrying the count shed since the last record.
	shedCount   int
	lastShedLog time.Time
}

// shedLogInterval bounds how often the pacer-shedding diagnostic is emitted, so a
// sustained overload logs a periodic coalesced record rather than one line per
// dropped frame.
const shedLogInterval = 1 * time.Second

// compile-time proof WeightedScheduler is a (dynamic) Scheduler.
var (
	_ Scheduler        = (*WeightedScheduler)(nil)
	_ DynamicScheduler = (*WeightedScheduler)(nil)
)

// NewWeighted builds the weighted-aggregation scheduler over parallel health and
// quality slices in priority order (index 0 = preferred primary). health and quality
// must be the same length; a quality element MAY be nil (that path then gets a
// neutral weight until a real PathQuality is wired). It fails fast on an empty or
// length-mismatched set, a nil health element, a nil dependency, or an invalid config.
func NewWeighted(health []PathHealth, quality []PathQuality, cfg WeightedConfig, clock telemetry.Clock, logger log.Logger) (*WeightedScheduler, error) {
	if len(health) == 0 {
		return nil, fmt.Errorf("sched: at least one path health source is required")
	}
	if len(quality) != len(health) {
		return nil, fmt.Errorf("sched: quality set (%d) must be one entry per health source (%d)", len(quality), len(health))
	}
	for i, h := range health {
		if h == nil {
			return nil, fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	if clock == nil {
		return nil, fmt.Errorf("sched: clock is required")
	}
	if logger == nil {
		return nil, fmt.Errorf("sched: logger is required")
	}
	if err := cfg.validate(); err != nil {
		return nil, err
	}
	return &WeightedScheduler{
		health:  append([]PathHealth(nil), health...),
		quality: append([]PathQuality(nil), quality...),
		clock:   clock,
		cfg:     cfg,
		log:     logger.Component("sched"),
		current: make([]float64, len(health)),
		tokens:  fullBuckets(len(health), cfg.PacingBurst),
		active:  -1,
	}, nil
}

// SetFEC installs the P3+ redundancy policy (nil clears it). It is the documented
// extension point for FEC-aware path selection; the current single-path Pick does
// not consult it (redundant transmission needs the P3 Bind fan-out), but
// RedundantPaths exposes it so a P3 Bind can query the additional paths per frame.
func (s *WeightedScheduler) SetFEC(fec FECPolicy) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.fec = fec
}

// RedundantPaths reports the ADDITIONAL path indices a frame scheduled onto chosen
// should also egress on, per the installed FECPolicy over the current eligible set.
// It returns nil when no policy is installed (no FEC). It is the P3 hook a redundant-
// transmission Bind would call alongside Pick; today it is a documented, unit-tested
// seam with no in-tree caller on the hot path.
func (s *WeightedScheduler) RedundantPaths(chosen int) []int {
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.fec == nil {
		return nil
	}
	return s.fec.RedundantPaths(chosen, s.eligibleLocked())
}

// Pick selects the path for the NEXT frame and advances all per-frame distribution
// state (offered-load meter, aggregation gate, pacing buckets, round-robin credits).
// It returns a negative value when no path is eligible OR when every eligible path
// is paced out (the frame is dropped rather than queued — pacing bounds egress and,
// by dropping the overflow, bounds the send backlog). It is safe for concurrent
// callers.
func (s *WeightedScheduler) Pick(class FrameClass) int {
	now := s.clock.Now()
	s.mu.Lock()
	defer s.mu.Unlock()

	// Capture the inter-sample idle gap BEFORE observeLoadLocked advances lastLoad: a
	// long gap since the previous offered frame is itself the strongest evidence of low
	// load, and the collapse hysteresis must count it (criticism #1 — otherwise an
	// abrupt overload stop leaves the gate engaged across the whole idle span and the
	// next low burst dribbles onto the metered path).
	gap := s.loadGapLocked(now)
	s.recomputeLocked(now)       // liveness refresh + eager-failover log
	s.observeLoadLocked(now)     // this Pick is one offered frame (decays across the gap)
	s.updateGateLocked(now, gap) // engage/disengage aggregation (hysteresis, idle-aware)
	s.refillLocked(now)          // top up pacing buckets

	eligible := s.eligibleLocked()
	if len(eligible) == 0 {
		return PickNone
	}
	if !s.aggregating {
		// Data-thrift: at low load only the primary (best eligible) carries traffic;
		// the metered backup stays idle. A path-down excludes it from eligible, so
		// eligible[0] is the surviving highest-priority path — failover is preserved.
		return s.serveLocked(now, eligible[0], class)
	}
	weights := s.weightsLocked(eligible)
	return s.selectAggregatingLocked(now, eligible, weights, class)
}

// loadGapLocked returns the wall-clock gap since the previous offered-load sample, or
// 0 before the first sample. Caller holds s.mu.
func (s *WeightedScheduler) loadGapLocked(now time.Time) time.Duration {
	if !s.haveLoad {
		return 0
	}
	gap := now.Sub(s.lastLoad)
	if gap < 0 {
		gap = 0
	}
	return gap
}

// Recompute refreshes only the liveness-derived eligible/active set from the current
// PathHealth and logs any active-path transition. It advances NONE of the per-frame
// distribution state (load meter, gate, pacing, round-robin credits), so the eager-
// failover nudge (defect D18/T40) drives an egress-lull failover recompute through it
// WITHOUT stealing a weighted-distribution slot the way a spurious Pick would. It is
// safe for concurrent callers.
func (s *WeightedScheduler) Recompute() {
	now := s.clock.Now()
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(now)
}

// recomputeLocked refreshes the active-primary cache (best eligible path) and logs a
// transition on change. Caller holds s.mu.
func (s *WeightedScheduler) recomputeLocked(_ time.Time) {
	best := s.bestEligibleLocked()
	s.setActiveLocked(best)
}

// serveLocked applies pacing to a single chosen path: it returns idx when the frame
// is admitted, or PickPaced when pacing is on and the path has no token (the frame is
// shed — dropped, bounding egress and backlog — and the shedding diagnostic is
// rate-limited). A ClassControl frame is pacing-EXEMPT (defect D22): it egresses on
// idx unconditionally, spending no token and never shed, so bulk overload cannot
// starve WireGuard rekey. Caller holds s.mu.
func (s *WeightedScheduler) serveLocked(now time.Time, idx int, class FrameClass) int {
	if class == ClassControl {
		return idx
	}
	if s.tryConsumeLocked(idx) {
		return idx
	}
	return s.shedLocked(now)
}

// selectAggregatingLocked picks a path proportional to weight (smooth weighted round
// robin) and applies pacing. When the round-robin's ideal pick is paced out it falls
// through to any other eligible path that still has a token, so aggregate egress is
// bounded by the SUM of the per-path paces; when every eligible path is paced out it
// sheds the frame (PickPaced). A ClassControl frame is pacing-EXEMPT (defect D22): it
// egresses on the weight-ideal path spending no token and is never shed, so bulk
// overload across every path cannot starve WireGuard rekey. Caller holds s.mu.
func (s *WeightedScheduler) selectAggregatingLocked(now time.Time, eligible []int, weights []float64, class FrameClass) int {
	ideal := s.swrrPickLocked(eligible, weights)
	if class == ClassControl {
		return ideal
	}
	if s.tryConsumeLocked(ideal) {
		return ideal
	}
	for _, gi := range eligible {
		if gi == ideal {
			continue
		}
		if s.tryConsumeLocked(gi) {
			return gi
		}
	}
	return s.shedLocked(now)
}

// shedLocked records one paced-out (shed) frame and emits the coalesced "pacer
// shedding" diagnostic at most once per shedLogInterval. It returns PickPaced so the
// Send path can map the drop to a distinct, non-outage error/log (criticism #3): the
// paths are healthy, this is deliberate rate limiting. Caller holds s.mu.
func (s *WeightedScheduler) shedLocked(now time.Time) int {
	s.shedCount++
	if s.lastShedLog.IsZero() || now.Sub(s.lastShedLog) >= shedLogInterval {
		s.log.Info("scheduler pacer shedding",
			"shed_frames", s.shedCount,
			"load_fps", s.loadRate,
		)
		s.lastShedLog = now
		s.shedCount = 0
	}
	return PickPaced
}

// swrrPickLocked is nginx's smooth weighted round-robin over the eligible set: it
// advances each eligible path's credit by its weight, picks the max-credit path, and
// subtracts the total weight from the winner. Over many calls the selection frequency
// of each path converges to its weight share, interleaved smoothly rather than
// bursted. Caller holds s.mu; weights is aligned to eligible order.
func (s *WeightedScheduler) swrrPickLocked(eligible []int, weights []float64) int {
	var total float64
	for _, w := range weights {
		total += w
	}
	best := -1
	var bestCur float64
	for k, gi := range eligible {
		s.current[gi] += weights[k]
		if best < 0 || s.current[gi] > bestCur {
			best = gi
			bestCur = s.current[gi]
		}
	}
	s.current[best] -= total
	return best
}

// weightsLocked computes the normalized Mathis-style weight for each eligible path
// from its PathQuality Estimate (RTT/loss). A path with NO usable quality — a nil
// quality source, or an all-zero Estimate (RTT==0: no probe sample yet) — is treated
// as genuinely NEUTRAL: it receives the MEAN of the measured paths' weights, so an
// unwired/cold path splits evenly rather than dominating. This matters because the
// floors would otherwise hand an all-zero Estimate the MAXIMUM weight (RTT floored to
// WeightRTTFloor, zero loss), letting a health-only path admitted via AddPath siphon
// the dominant share — the opposite of neutral. When every eligible path is neutral,
// all get equal weight. Caller holds s.mu; the result is aligned to eligible order and
// sums to 1.
func (s *WeightedScheduler) weightsLocked(eligible []int) []float64 {
	w := make([]float64, len(eligible))
	measured := make([]bool, len(eligible))
	rttFloor := float64(s.cfg.WeightRTTFloor)
	var sumMeasured float64
	nMeasured := 0
	for k, gi := range eligible {
		q := s.quality[gi]
		if q == nil {
			continue // unwired: neutral, filled below
		}
		est := q.Estimate()
		if est.RTT <= 0 {
			continue // no RTT sample yet (cold estimator): neutral, filled below
		}
		rtt := float64(est.RTT)
		if rtt < rttFloor {
			rtt = rttFloor
		}
		loss := est.Loss
		if loss < 0 {
			loss = 0
		}
		wi := 1.0 / (rtt * math.Sqrt(loss+s.cfg.WeightLossFloor))
		w[k] = wi
		measured[k] = true
		sumMeasured += wi
		nMeasured++
	}
	// Neutral weight: the mean of the measured weights (so a neutral path splits evenly
	// with the measured set, never outweighing it); equal weights when nothing measured.
	neutral := 1.0
	if nMeasured > 0 {
		neutral = sumMeasured / float64(nMeasured)
	}
	var sum float64
	for k := range w {
		if !measured[k] {
			w[k] = neutral
		}
		sum += w[k]
	}
	if sum <= 0 {
		for k := range w {
			w[k] = 1.0 / float64(len(w))
		}
		return w
	}
	for k := range w {
		w[k] /= sum
	}
	return w
}

// observeLoadLocked folds one offered frame into the exponentially-weighted event-
// rate estimator. Each event adds 1/tau (per-second units) after decaying the prior
// estimate by exp(-dt/tau); the steady-state estimate converges to the offered rate
// in events/sec. It is robust to dt==0 (many Picks at one clock instant just add
// without decay). Caller holds s.mu.
func (s *WeightedScheduler) observeLoadLocked(now time.Time) {
	tau := s.cfg.LoadTau.Seconds()
	if !s.haveLoad {
		s.haveLoad = true
		s.lastLoad = now
		s.loadRate = 0
	} else {
		dt := now.Sub(s.lastLoad).Seconds()
		if dt < 0 {
			dt = 0
		}
		s.loadRate *= math.Exp(-dt / tau)
		s.lastLoad = now
	}
	s.loadRate += 1.0 / tau
}

// updateGateLocked engages or disengages aggregation from the smoothed offered load,
// with hysteresis: engage the instant load exceeds EngageFraction*capacity; collapse
// back to primary-only only after load stays below DisengageFraction*capacity for
// CollapseDwell. The two-threshold band plus the dwell keep the metered path from
// flapping on/off around a single point (requirement 2). gap is the wall-clock idle
// span since the previous offered frame.
//
// Idle time IS low load (criticism #1). The gate only advances on a Pick, so an
// overload that stops ABRUPTLY (load still above disengage on the last frame) would
// otherwise stay engaged across an arbitrarily long idle span and stripe the first
// ~CollapseDwell of the NEXT low burst onto the metered backup — a data-thrift leak.
// Two provisions close it: (a) an idle gap that alone reaches CollapseDwell forces an
// immediate collapse, since a gap that long is itself proof of sustained low load; and
// (b) belowSince is BACKDATED to when load actually dropped (the previous sample,
// now-gap) rather than seeded at this post-idle frame, so the dwell counts the idle.
// The load EWMA decays across gap in observeLoadLocked, so a post-idle frame reads
// ~0 and the collapse fires on the FIRST frame of the next burst. Caller holds s.mu.
func (s *WeightedScheduler) updateGateLocked(now time.Time, gap time.Duration) {
	engage := s.cfg.EngageFraction * s.cfg.PerPathCapacity
	disengage := s.cfg.DisengageFraction * s.cfg.PerPathCapacity
	if !s.aggregating {
		if s.loadRate > engage {
			s.aggregating = true
			s.belowSince = time.Time{}
			s.log.Info("scheduler aggregation change", "to", "aggregating", "load_fps", s.loadRate)
		}
		return
	}
	// (a) A single idle gap of at least the dwell is conclusive: collapse now.
	if gap >= s.cfg.CollapseDwell {
		s.aggregating = false
		s.belowSince = time.Time{}
		s.log.Info("scheduler aggregation change", "to", "collapsed", "reason", "idle gap", "gap", gap.String())
		return
	}
	if s.loadRate < disengage {
		if s.belowSince.IsZero() {
			// (b) Backdate to when load dropped: the previous sample (now-gap), not this
			// post-idle frame, so the idle span counts toward the dwell.
			s.belowSince = now.Add(-gap)
		}
		if now.Sub(s.belowSince) >= s.cfg.CollapseDwell {
			s.aggregating = false
			s.belowSince = time.Time{}
			s.log.Info("scheduler aggregation change", "to", "collapsed", "reason", "sustained low load", "load_fps", s.loadRate)
		}
		return
	}
	// Load rose back above the disengage threshold: reset the collapse dwell.
	s.belowSince = time.Time{}
}

// refillLocked tops up every per-path token bucket by PerPathCapacity·elapsed, capped
// at PacingBurst. The first call seeds every bucket full. It is a no-op accountant
// when pacing is disabled (tryConsumeLocked always admits), but the buckets are still
// maintained so toggling pacing needs no re-seed. Caller holds s.mu.
func (s *WeightedScheduler) refillLocked(now time.Time) {
	if !s.haveFill {
		s.haveFill = true
		s.lastFill = now
		for i := range s.tokens {
			s.tokens[i] = s.cfg.PacingBurst
		}
		return
	}
	dt := now.Sub(s.lastFill).Seconds()
	if dt < 0 {
		dt = 0
	}
	add := s.cfg.PerPathCapacity * dt
	for i := range s.tokens {
		s.tokens[i] += add
		if s.tokens[i] > s.cfg.PacingBurst {
			s.tokens[i] = s.cfg.PacingBurst
		}
	}
	s.lastFill = now
}

// tryConsumeLocked spends one token from path idx's bucket, reporting whether the
// frame is admitted. With pacing disabled it always admits (the buckets are inert).
// Caller holds s.mu.
func (s *WeightedScheduler) tryConsumeLocked(idx int) bool {
	if !s.cfg.Pacing {
		return true
	}
	if s.tokens[idx] >= 1 {
		s.tokens[idx]--
		return true
	}
	return false
}

// eligibleLocked returns the global indices of paths reporting StateUp, in priority
// order. Caller holds s.mu.
func (s *WeightedScheduler) eligibleLocked() []int {
	e := make([]int, 0, len(s.health))
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			e = append(e, i)
		}
	}
	return e
}

// bestEligibleLocked returns the lowest-index path reporting StateUp, or -1.
func (s *WeightedScheduler) bestEligibleLocked() int {
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			return i
		}
	}
	return -1
}

// setActiveLocked stores the active-primary index and logs a transition only when it
// changes, so a saturated send path does not log on every Pick. The message matches
// ActiveBackup's ("scheduler active path change") so downstream log parsing (the e2e
// failover harness) reads either policy identically.
func (s *WeightedScheduler) setActiveLocked(idx int) {
	if s.active == idx {
		return
	}
	from := s.active
	s.active = idx
	s.log.Info("scheduler active path change", "from", from, "to", idx, "reason", "weighted recompute")
}

// AddPath admits h as a new lowest-priority path and returns its index (the new
// tail). Its quality source is h itself when h also satisfies PathQuality (the
// production *Prober does); a health-ONLY source (no PathQuality) is recorded with a
// nil quality and weightsLocked then gives it the NEUTRAL (mean) weight, so it splits
// evenly and never siphons the dominant share. Appending at the tail leaves every
// existing index unchanged and the new path only carries traffic once aggregation
// engages, so a runtime admission never disturbs the surviving paths' distribution
// (T30). It is safe for concurrent callers.
func (s *WeightedScheduler) AddPath(h PathHealth) (int, error) {
	if h == nil {
		return 0, fmt.Errorf("sched: cannot add a nil path health source")
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append(s.health, h)
	s.quality = append(s.quality, asQuality(h))
	s.current = append(s.current, 0)
	s.tokens = append(s.tokens, s.cfg.PacingBurst)
	return len(s.health) - 1, nil
}

// RemovePath drops the path at index i (shifting higher indices down by one) and
// clears the cached active selection so the next Pick/Recompute re-derives it from
// live liveness. The round-robin credits are positional and compacted with the path
// list; a brief re-warm of the smoothing after a membership change is harmless. It is
// safe for concurrent callers.
func (s *WeightedScheduler) RemovePath(i int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if i < 0 || i >= len(s.health) {
		return fmt.Errorf("sched: remove path index %d out of range [0,%d)", i, len(s.health))
	}
	s.health = append(s.health[:i], s.health[i+1:]...)
	s.quality = append(s.quality[:i], s.quality[i+1:]...)
	s.current = append(s.current[:i], s.current[i+1:]...)
	s.tokens = append(s.tokens[:i], s.tokens[i+1:]...)
	s.active = -1
	return nil
}

// SetPaths replaces the entire health list (priority order, index 0 = preferred
// primary), rebuilding the parallel quality slice from the new sources, resetting the
// round-robin credits and pacing buckets, and collapsing aggregation to primary-only
// so the next Pick re-derives everything from live liveness. The Bind calls it on
// every Open to re-align the scheduler with the freshly-rebuilt path slice (T30). It
// fails fast on an empty set or a nil element, matching NewWeighted. It is safe for
// concurrent callers.
func (s *WeightedScheduler) SetPaths(health []PathHealth) error {
	if len(health) == 0 {
		return fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append([]PathHealth(nil), health...)
	s.quality = make([]PathQuality, len(health))
	for i, h := range health {
		s.quality[i] = asQuality(h)
	}
	s.current = make([]float64, len(health))
	s.tokens = fullBuckets(len(health), s.cfg.PacingBurst)
	s.haveFill = false
	s.aggregating = false
	s.belowSince = time.Time{}
	s.active = -1
	return nil
}

// asQuality returns h as a PathQuality when it also implements that interface (the
// production *telemetry.Prober does — one source drives both liveness and weight), or
// nil so the path gets a neutral weight.
func asQuality(h PathHealth) PathQuality {
	if q, ok := h.(PathQuality); ok {
		return q
	}
	return nil
}

// fullBuckets returns n token buckets each seeded to burst.
func fullBuckets(n int, burst float64) []float64 {
	t := make([]float64, n)
	for i := range t {
		t[i] = burst
	}
	return t
}

package config

import (
	"encoding/base64"
	"encoding/hex"
	"errors"
	"fmt"
	"math"
	"net"
	"net/netip"
	"strconv"
	"strings"
	"time"

	awgdevice "github.com/amnezia-vpn/amneziawg-go/device"
)

// Role selects which end of the tunnel this process runs as. It is an explicit,
// required field; the role is never inferred from other configuration.
type Role string

const (
	// RoleEdge is the mobile Linux box that bonds the WAN uplinks.
	RoleEdge Role = "edge"
	// RoleConcentrator is the public-IP VPS that terminates the tunnel.
	RoleConcentrator Role = "concentrator"
)

func (r Role) valid() bool {
	return r == RoleEdge || r == RoleConcentrator
}

// keyLen is the byte length of a Curve25519 WireGuard key and of a raw
// outer-control PSK, before base64 encoding.
const keyLen = 32

// Config is the whole wanbond configuration, shared by both roles and parsed
// from a single TOML file.
type Config struct {
	Role      Role            `toml:"role"`
	Paths     []Path          `toml:"paths"`
	WireGuard WireGuard       `toml:"wireguard"`
	Amnezia   Amnezia         `toml:"amnezia"`
	PSK       Key             `toml:"psk"`
	Metrics   Metrics         `toml:"metrics"`
	Log       Log             `toml:"log"`
	Scheduler SchedulerConfig `toml:"scheduler"`
	FEC       FEC             `toml:"fec"`
	DNS       DNS             `toml:"dns"`
	// Bind is the OPTIONAL top-level default bind mode (I5, Q42) applied to every
	// path that omits its own `bind`. Left empty it defaults to BindModeAuto
	// (today's selectDeviceBinds heuristic) in normalize(), so an existing config
	// with no `bind` anywhere keeps exactly today's per-path bind behaviour.
	Bind BindMode `toml:"bind"`
	// TUNPersist opts wanbond0 into surviving daemon restarts (I7, Q38). Default
	// false keeps today's teardown semantics exactly: the TUN is non-persistent
	// and the kernel destroys it when the daemon's last fd closes on Close, so
	// addresses/routes/rules referencing it are dropped on every restart. Set true
	// and the daemon issues TUNSETPERSIST on start (device.Up) — the link then
	// outlives Close (amneziawg-go's NativeTun.Close only closes the fd/netlink
	// socket; it never issues RTM_DELLINK), and the next start re-adopts the same
	// persistent device BY NAME via CreateTUN's TUNSETIFF, preserving its ifindex
	// so operator-owned addressing survives untouched. On an NM host a persistent
	// device STILL needs the unmanaged-devices drop-in (D39) — persistence keeps
	// the link across restarts but does not exempt it from NetworkManager.
	TUNPersist bool `toml:"tun_persist"`
}

// BindMode selects, per path, how that path's UDP socket is bound to the
// network at Open time (I5, Q42):
//
//   - BindModeAuto reproduces today's selectDeviceBinds heuristic: device-bind
//     (SO_BINDTODEVICE) only when provably equivalent to pinning source_addr,
//     source-IP-bind otherwise.
//   - BindModeSource forces the pre-T16 source-IP pin unconditionally.
//   - BindModeDevice forces a device bind unconditionally.
type BindMode string

const (
	// BindModeSource forces the source-IP pin (pre-T16 behaviour).
	BindModeSource BindMode = "source"
	// BindModeDevice forces a device bind (SO_BINDTODEVICE).
	BindModeDevice BindMode = "device"
	// BindModeAuto reproduces today's selectDeviceBinds heuristic. It is the
	// default when a path (and the top-level default) both omit `bind`.
	BindModeAuto BindMode = "auto"
)

func (b BindMode) valid() bool {
	return b == BindModeSource || b == BindModeDevice || b == BindModeAuto
}

// SchedulerPolicy selects the send-side path-selection policy the multipath Bind
// runs. It is a bounded enum: the P1 active-backup failover (default) or the T21
// weighted-aggregation policy. The policy is an explicit config choice — active-
// backup stays selectable so the P1 behaviour is never removed, only extended.
type SchedulerPolicy string

const (
	// PolicyActiveBackup is the P1 single-active-path failover scheduler: all egress
	// on the highest-priority live path, every other path idle (data-thrift by
	// construction). It is the default when [scheduler] is omitted.
	PolicyActiveBackup SchedulerPolicy = "active-backup"
	// PolicyWeighted is the T21 weighted-aggregation scheduler: under load a single
	// flow is striped across both paths in proportion to per-path RTT/loss-derived
	// weight, collapsing to the primary at low load (5G stays ~idle) with hysteresis,
	// and per-path send-pacing to bound bufferbloat.
	PolicyWeighted SchedulerPolicy = "weighted"
)

func (p SchedulerPolicy) valid() bool {
	return p == PolicyActiveBackup || p == PolicyWeighted
}

// Weighted-aggregation policy defaults (T21). They are applied when [scheduler]
// selects the weighted policy but leaves a knob at its zero value, so a minimal
// `policy = "weighted"` block is usable without hand-tuning every threshold. They
// are conservative bring-up values; the empirical per-path pace is sized from a
// measured BDP in a bandwidth-capped fixture (P0 findings §7, deferred to T35/T23),
// so the shipped default leaves pacing DISABLED and only bounds distribution.
const (
	// defaultPerPathCapacityFPS is the reference per-path capacity, in frame-selection
	// slots per second, that the aggregation load-gate compares offered load against
	// AND (when pacing is enabled) the per-path token-bucket refill rate. It is a
	// synthetic proxy for path capacity: there is no measured BDP (P0 §7), so capacity
	// is expressed in the only unit the scheduler sees — Pick() invocations per second.
	defaultPerPathCapacityFPS = 10000.0
	// defaultEngageFraction engages aggregation once offered load exceeds this
	// fraction of one path's capacity — i.e. a single path is nearly saturated.
	defaultEngageFraction = 0.9
	// defaultDisengageFraction collapses back to primary-only once offered load falls
	// below this fraction of one path's capacity. It is strictly below the engage
	// fraction: the gap is the hysteresis band that stops the 5G path from dribbling
	// on/off around a single threshold (requirement 2, data-thrift).
	defaultDisengageFraction = 0.5
	// defaultCollapseDwell is how long offered load must stay continuously below the
	// disengage fraction before aggregation collapses to primary-only — the temporal
	// half of the hysteresis, mirroring the active-backup failback dwell so a brief
	// lull does not repeatedly park then re-engage the metered path.
	defaultCollapseDwell = 2 * time.Second
	// defaultLoadTau is the time constant of the exponentially-weighted offered-load
	// rate estimator. It smooths the instantaneous Pick() arrival rate so the gate
	// reacts to sustained load, not single-frame bursts.
	defaultLoadTau = 200 * time.Millisecond
	// defaultPacingBurstFrames is the per-path token-bucket burst (in frame slots)
	// when pacing is enabled: the bucket admits up to this many frames instantaneously
	// before the refill rate binds, absorbing normal jitter without inflating a queue.
	defaultPacingBurstFrames = 64.0
	// defaultWeightRTTFloor floors the RTT in the weight formula so a path reporting a
	// near-zero RTT (cold estimator, no samples yet) cannot be handed unbounded weight.
	defaultWeightRTTFloor = 1 * time.Millisecond
	// defaultWeightLossFloor floors the loss term under the square root so a zero-loss
	// path gets a large-but-finite weight and two zero-loss paths split by inverse-RTT
	// alone rather than both diverging.
	defaultWeightLossFloor = 1e-3
)

// SchedulerConfig selects and tunes the send scheduler. When the [scheduler] block
// is omitted the policy defaults to active-backup and every weighted knob is
// ignored, so existing configs keep the P1 behaviour unchanged. The weighted knobs
// are validated (and defaulted) only when the weighted policy is selected.
type SchedulerConfig struct {
	// Policy selects the scheduler; defaults to active-backup when empty.
	Policy SchedulerPolicy `toml:"policy"`

	// PerPathCapacityFPS is the reference per-path capacity in frame-selection slots
	// per second: the denominator the aggregation load-gate compares offered load
	// against, and the per-path pacing refill rate when PacingEnabled. Must be > 0
	// under the weighted policy.
	PerPathCapacityFPS float64 `toml:"per_path_capacity_fps"`
	// EngageFraction engages aggregation when offered load exceeds
	// EngageFraction*PerPathCapacityFPS. Must be in (0,1].
	EngageFraction float64 `toml:"engage_fraction"`
	// DisengageFraction collapses aggregation to primary-only once offered load stays
	// below DisengageFraction*PerPathCapacityFPS for CollapseDwell. Must be in
	// [0,EngageFraction) — strictly below EngageFraction so the two form a hysteresis
	// band.
	DisengageFraction float64 `toml:"disengage_fraction"`
	// CollapseDwell is the sustained-low-load dwell before collapsing to primary-only
	// (hysteresis). Must be >= 0. Parsed from CollapseDwellRaw in normalize.
	CollapseDwell time.Duration `toml:"-"`
	// CollapseDwellRaw is the TOML Go-duration string form of CollapseDwell, e.g.
	// "2s" (D43). Parsed in normalize; an unparseable value fails fast, mirroring
	// Path.LinkRTTRaw.
	CollapseDwellRaw string `toml:"collapse_dwell"`
	// LoadTau is the offered-load rate estimator's time constant. Must be > 0. Parsed
	// from LoadTauRaw in normalize.
	LoadTau time.Duration `toml:"-"`
	// LoadTauRaw is the TOML Go-duration string form of LoadTau, e.g. "200ms" (D43).
	// Parsed in normalize; an unparseable value fails fast.
	LoadTauRaw string `toml:"load_tau"`

	// PacingEnabled turns per-path send-pacing on. When false the token buckets are
	// bypassed (a documented no-op — P0 §7 could not empirically size the pace in the
	// unmetered fixture), but PerPathCapacityFPS still drives the aggregation gate.
	PacingEnabled bool `toml:"pacing_enabled"`
	// PacingBurstFrames is the per-path token-bucket burst in frame slots. Must be > 0
	// when PacingEnabled.
	PacingBurstFrames float64 `toml:"pacing_burst_frames"`

	// WeightRTTFloor floors RTT in the weight formula (must be > 0 under weighted).
	// Parsed from WeightRTTFloorRaw in normalize.
	WeightRTTFloor time.Duration `toml:"-"`
	// WeightRTTFloorRaw is the TOML Go-duration string form of WeightRTTFloor, e.g.
	// "1ms" (D43). Parsed in normalize; an unparseable value fails fast.
	WeightRTTFloorRaw string `toml:"weight_rtt_floor"`
	// WeightLossFloor floors the loss term under the square root (must be > 0 under
	// weighted).
	WeightLossFloor float64 `toml:"weight_loss_floor"`
}

// BDPSizing is a per-path pacing sizing derived from a MEASURED path, in the
// frame-selection-slot units the weighted scheduler pace uses (defect D22). It is the
// empirical alternative to the synthetic frame-count defaults: CapacityFPS replaces
// PerPathCapacityFPS and BurstFrames replaces PacingBurstFrames.
type BDPSizing struct {
	// CapacityFPS is the sustained per-path frame rate the measured bottleneck bandwidth
	// supports (the token-bucket refill rate and aggregation-gate denominator).
	CapacityFPS float64
	// BurstFrames is the bandwidth-delay product expressed in frames (bandwidth x RTT,
	// i.e. one RTT of in-flight frames): the token-bucket burst that absorbs one RTT of
	// jitter without building a standing queue.
	BurstFrames float64
}

// defaultAvgWireFrameBytes is the conservative average on-wire outer-frame size used
// when deriving the per-path pace from an operator-declared bandwidth at config load
// (T53): a full IPv4 path MTU, since a full-MTU DATA datagram occupies about one path
// MTU on the wire. It mirrors bind.DefaultPathMTU (1500) rather than importing it —
// internal/bind imports internal/config, so config cannot import bind without a cycle
// (the same mirror-with-cross-reference pattern as maxFECDeadline above). Sizing
// capacity with the full-MTU frame is the conservative floor: smaller average frames
// would yield a HIGHER frame rate, so this never over-paces a path.
const defaultAvgWireFrameBytes = 1500.0

// SizePacingFromBDP derives the weighted scheduler's per-path pacing parameters from a
// measured path instead of the synthetic frame-count default (defect D22). The shipped
// defaultPerPathCapacityFPS (10000, ~115 Mbit/s at full MTU) sits far above a realistic
// slow uplink, so the aggregation gate may never engage and — with pacing enabled — the
// pace never binds; deriving capacity from the measured bottleneck bandwidth fixes both.
//
// capacity_fps = bandwidth / (8 * avg wire frame bytes) — frames/s the link sustains.
// burst_frames = capacity_fps * RTT — one RTT of in-flight frames (equivalently
// BDP_bytes / avg wire frame bytes, since the bandwidth-delay product BDP = bandwidth * RTT).
//
// bandwidthBitsPerSec is the measured bottleneck bandwidth (bits/s), rtt the measured
// path RTT, and avgWireFrameBytes the average on-wire outer-frame size (a full-MTU
// datagram plus frame.DataOverhead is the conservative choice). It fails fast on a
// non-positive input rather than emitting a nonsensical (zero/negative/Inf) sizing.
func SizePacingFromBDP(bandwidthBitsPerSec float64, rtt time.Duration, avgWireFrameBytes float64) (BDPSizing, error) {
	if bandwidthBitsPerSec <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing bandwidth must be > 0 bit/s, got %g", bandwidthBitsPerSec)
	}
	if rtt <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing RTT must be > 0, got %s", rtt)
	}
	if avgWireFrameBytes <= 0 {
		return BDPSizing{}, fmt.Errorf("config: BDP sizing average wire frame size must be > 0 bytes, got %g", avgWireFrameBytes)
	}
	const bitsPerByte = 8.0
	capacityFPS := bandwidthBitsPerSec / (bitsPerByte * avgWireFrameBytes)
	burstFrames := capacityFPS * rtt.Seconds()
	return BDPSizing{CapacityFPS: capacityFPS, BurstFrames: burstFrames}, nil
}

// bandwidthUnit is a recognised link_bandwidth suffix and its bit/s multiplier.
type bandwidthUnit struct {
	suffix string
	mult   float64
}

// bandwidthUnits are the accepted operator-facing bandwidth suffixes, longest-first so
// "gbit" is matched before "bit". SI decimal multipliers (k/M/G = 1e3/1e6/1e9) over a
// bit/s base; "bps" is accepted as an alias of "bit" (and "kbps"/"mbps"/"gbps" likewise).
var bandwidthUnits = []bandwidthUnit{
	{"gbit", 1e9}, {"gbps", 1e9},
	{"mbit", 1e6}, {"mbps", 1e6},
	{"kbit", 1e3}, {"kbps", 1e3},
	{"bit", 1}, {"bps", 1},
}

// parseBandwidth parses an operator-declared link bandwidth such as "50Mbit", "1Gbit",
// or "500kbit" into bits per second. It requires an explicit bit/s unit suffix so a
// bare unitless number cannot be silently misread, and fails fast on an empty or
// otherwise unparseable value — a mistyped bandwidth is rejected at config load.
func parseBandwidth(s string) (float64, error) {
	lower := strings.ToLower(strings.TrimSpace(s))
	if lower == "" {
		return 0, errors.New("empty bandwidth")
	}
	for _, u := range bandwidthUnits {
		if !strings.HasSuffix(lower, u.suffix) {
			continue
		}
		num := strings.TrimSpace(lower[:len(lower)-len(u.suffix)])
		val, err := strconv.ParseFloat(num, 64)
		if err != nil {
			return 0, fmt.Errorf("invalid number %q", num)
		}
		return val * u.mult, nil
	}
	return 0, fmt.Errorf("missing bit/s unit suffix (want e.g. %q)", "50Mbit")
}

// FEC group-close deadline default (T24). Applied only when [fec] is enabled but
// leaves the deadline at its zero value, so a minimal `enabled = true` block emits
// parity for a partially-filled group promptly under low load rather than stranding
// it until the size threshold fills.
const defaultFECDeadline = 5 * time.Millisecond

// defaultAdaptiveSafetyFactor mirrors adaptivefec.DefaultSafetyFactor (1.5), the
// simulation-proven controller default, restated here (with this cross-reference rather
// than an import) so a minimal `adaptive = true` block gets the proven tuning without
// coupling config to the controller package. NOTE: 1.5 sizes M for the mean loss with
// modest variance headroom; a tight residual SLA under a specific loss/geometry may need a
// higher factor (e.g. at 5% loss with K=10 the 1.5 default sizes M=1, ~1% residual — raise
// this to lift M and drive the residual down).
const defaultAdaptiveSafetyFactor = 1.5

// maxFECDeadline bounds the FEC group-close deadline at load time (T24, defect #4). It
// MUST stay at or below the multipath Bind's authoritative bound (bind.maxFECDeadline =
// resequencerTimeout/2 = 125ms): a group flushed by the deadline emits its parity
// `deadline` after opening, and the reconstructed frames must reach the receive
// resequencer BEFORE it skips the gap (its 250ms per-gap timeout) — otherwise recovery
// is structurally too late (the gap is skipped, the recovered frame dropped as past the
// release point) while /metrics would still count it reconstructed. Rejecting an
// over-large deadline at load makes that coupling fail-fast and explicit rather than
// silently defeating FEC. Kept in lockstep with bind.maxFECDeadline (the packages
// cannot import each other, so the value is mirrored with this cross-reference).
const maxFECDeadline = 125 * time.Millisecond

// maxFECShards mirrors the Reed-Solomon field limit enforced in internal/fec: a
// coding group carries at most 256 shards (data + parity) total over GF(2^8). It
// is restated here so config load fails fast on an over-large ratio at the right
// locus, with the same bound the codec enforces internally.
const maxFECShards = 256

// FEC configures the fixed-ratio Reed-Solomon forward-error-correction plane (T24).
// It is DISABLED by default (like pacing), so an existing config with no [fec] block
// runs the datapath exactly as before — FEC transparent, no parity on the wire. When
// enabled, each group of DataShards (K) inner datagrams is protected by ParityShards
// (M) parity frames, letting the receiver reconstruct up to M lost data frames per
// group at a fixed M/K parity overhead.
type FEC struct {
	// Enabled turns the FEC plane on. When false every other field is ignored and the
	// datapath carries no parity.
	Enabled bool `toml:"enabled"`
	// DataShards is K: the number of inner datagrams grouped before parity is emitted.
	// Must be >= 1 when enabled.
	DataShards int `toml:"data_shards"`
	// ParityShards is M: the parity frames emitted per group and the maximum number of
	// per-group data losses the receiver can recover. Must be >= 1 when enabled. In
	// adaptive mode it is the CEILING (and the receiver's decoder cardinality) — the
	// controller drives the per-group parity in [0,ParityShards] to track measured loss.
	ParityShards int `toml:"parity_shards"`
	// Deadline bounds grouping latency: a partially-filled group is flushed (parity
	// emitted over its current data frames) once this much time has elapsed since its
	// first frame. Defaults to defaultFECDeadline when enabled and left zero; must be
	// > 0 after defaulting. Parsed from DeadlineRaw in normalize.
	Deadline time.Duration `toml:"-"`
	// DeadlineRaw is the TOML Go-duration string form of Deadline, e.g. "5ms" (D43).
	// Parsed in normalize; an unparseable value fails fast, mirroring Path.LinkRTTRaw.
	DeadlineRaw string `toml:"deadline"`
	// Adaptive opts the send-side FEC into the closed-loop controller (T27/T29): the
	// per-group parity count tracks the measured per-path loss instead of standing at
	// the fixed ParityShards ratio, so a clean path spends near-zero overhead while a
	// lossy one is masked. It is OFF by default, so an existing [fec] block keeps the
	// fixed-ratio behaviour (T24) byte-for-byte. When true, ParityShards is reinterpreted
	// as the controller's parity ceiling (see above); the receiver is unchanged because a
	// group coded with fewer parity shards decodes against the ParityShards-ceiling codec
	// unchanged (klauspost's parity is prefix-consistent).
	Adaptive bool `toml:"adaptive"`
	// SafetyFactor is the adaptive controller's headroom multiplier over the measured mean
	// loss the per-group parity is sized to mask (adaptivefec.Config.SafetyFactor). It is
	// the residual-loss LEVER: the controller sizes M so M/(K+M) >= SafetyFactor*loss, so a
	// higher factor spends more parity to keep the post-recovery residual under a tighter
	// bound against binomial per-group variance. Applies only in adaptive mode; defaults to
	// defaultAdaptiveSafetyFactor (the simulation-proven controller default) when left zero
	// AND target_residual is unset, and must be >= 1. Ignored (and must stay zero) in fixed
	// mode, and mutually exclusive with target_residual (set one, not both).
	SafetyFactor float64 `toml:"safety_factor"`
	// TargetResidual is the adaptive controller's target POST-RECOVERY residual-loss SLA
	// (a fraction in (0,1)) and the PRIMARY adaptive sizing surface (D26/T46): the
	// controller derives the per-group parity M by inverting the binomial residual model
	// E[max(0,D-M)]/K (D ~ Bin(K, smoothed loss)) to the smallest M meeting this target,
	// capped at the parity ceiling (parity_shards). It SUPERSEDES safety_factor — set
	// EITHER a residual SLA (target_residual, recommended: it maps an operator's loss
	// budget directly to redundancy) OR the bare headroom multiplier (safety_factor), never
	// both. Applies only in adaptive mode; unset (0) selects the safety_factor path. Must
	// be in (0,1) when set. Ignored (and must stay zero) in fixed mode.
	TargetResidual float64 `toml:"target_residual"`
}

// parseDurations parses DeadlineRaw into the typed Deadline field (D43), mirroring
// the Path.LinkRTTRaw precedent: go-toml/v2 cannot decode a TOML string into a bare
// time.Duration, so the documented `deadline = "5ms"` form would otherwise fail to
// load. An empty DeadlineRaw leaves Deadline at zero so applyDefaults' zero-check
// still fills defaultFECDeadline. Only the parse itself is fail-fast here (unparseable
// duration syntax); the >0/<=maxFECDeadline range checks stay in validate(), unchanged.
func (f *FEC) parseDurations() error {
	if f.DeadlineRaw != "" {
		d, err := time.ParseDuration(f.DeadlineRaw)
		if err != nil {
			return fmt.Errorf("fec.deadline: invalid duration %q: %w", f.DeadlineRaw, err)
		}
		f.Deadline = d
	}
	return nil
}

// applyDefaults fills the group-close deadline when FEC is enabled and the deadline
// was left at zero. It is a no-op for a disabled block, so a config that never turns
// FEC on keeps an empty [fec] surface.
func (f *FEC) applyDefaults() {
	if !f.Enabled {
		return
	}
	if f.Deadline == 0 {
		f.Deadline = defaultFECDeadline
	}
	// The SafetyFactor default is applied only in the legacy sizing mode: when
	// target_residual is set it is the primary surface and safety_factor stays inert
	// (0), so defaulting it would spuriously trip the mutual-exclusion check.
	if f.Adaptive && f.TargetResidual == 0 && f.SafetyFactor == 0 {
		f.SafetyFactor = defaultAdaptiveSafetyFactor
	}
}

// validate enforces the FEC ratio invariants, failing fast so a mis-tuned parity
// ratio is rejected at load rather than panicking the codec at runtime. A disabled
// block needs no tuning. The bounds mirror internal/fec's own Config.validate.
func (f FEC) validate() error {
	if !f.Enabled {
		if f.Adaptive {
			return errors.New("fec.adaptive = true requires fec.enabled = true (adaptive FEC is meaningless with the plane off)")
		}
		return nil
	}
	if f.DataShards < 1 {
		return fmt.Errorf("fec.data_shards must be >= 1 when FEC is enabled, got %d", f.DataShards)
	}
	if f.ParityShards < 1 {
		return fmt.Errorf("fec.parity_shards must be >= 1 when FEC is enabled, got %d", f.ParityShards)
	}
	if f.DataShards+f.ParityShards > maxFECShards {
		return fmt.Errorf("fec.data_shards + fec.parity_shards must be <= %d (Reed-Solomon field limit), got %d", maxFECShards, f.DataShards+f.ParityShards)
	}
	if f.Deadline <= 0 {
		return fmt.Errorf("fec.deadline must be > 0 when FEC is enabled, got %s", f.Deadline)
	}
	if f.Deadline > maxFECDeadline {
		return fmt.Errorf("fec.deadline must be <= %s (safely below the receive resequencer's per-gap timeout so deadline-flushed recovery lands before the gap is skipped), got %s", maxFECDeadline, f.Deadline)
	}
	if f.Adaptive {
		if f.TargetResidual != 0 {
			// Residual-SLA sizing mode (primary): target_residual governs and safety_factor
			// stays inert, so setting both is an ambiguous mis-config — reject it. NaN is
			// caught explicitly because every ordered comparison against it is false.
			if math.IsNaN(f.TargetResidual) || f.TargetResidual <= 0 || f.TargetResidual >= 1 {
				return fmt.Errorf("fec.target_residual must be a finite value in (0,1), got %g", f.TargetResidual)
			}
			if f.SafetyFactor != 0 {
				return fmt.Errorf("fec.safety_factor and fec.target_residual are mutually exclusive; target_residual is the primary residual-SLA surface — set one, not both")
			}
		} else if f.SafetyFactor < 1 {
			// SafetyFactor is defaulted to defaultAdaptiveSafetyFactor when zero, so a value
			// below 1 here is an explicit mis-set: the controller requires >= 1 (masking less
			// than the mean loss is nonsensical), matching adaptivefec.Config.Validate.
			return fmt.Errorf("fec.safety_factor must be >= 1 in adaptive mode, got %g", f.SafetyFactor)
		}
	} else if f.SafetyFactor != 0 || f.TargetResidual != 0 {
		return fmt.Errorf("fec.safety_factor / fec.target_residual are only meaningful in adaptive mode (set fec.adaptive = true), got safety_factor=%g target_residual=%g", f.SafetyFactor, f.TargetResidual)
	}
	return nil
}

// Path is one physical WAN uplink. The edge binds each path's UDP socket to
// SourceAddr so the upstream router pins it to the intended WAN; the
// concentrator learns the real per-path endpoints from authenticated traffic.
type Path struct {
	// Name is a stable human-readable identifier for the path (e.g. "starlink").
	Name string `toml:"name"`
	// SourceAddr is the local source IP the path's socket binds to.
	SourceAddr netip.Addr `toml:"-"`
	// SourceAddrRaw is the TOML string form of SourceAddr; parsed in normalize.
	SourceAddrRaw string `toml:"source_addr"`
	// DestAddr is the OPTIONAL per-path concentrator endpoint ("ip:port") the
	// edge sends this path's datagrams to. It is unset on the concentrator (which
	// learns edge endpoints from traffic) and optional on the edge: when a single
	// public concentrator IP fronts all uplinks (the common source-routed case)
	// the peer's wireguard endpoint is reused for every path; when the paths reach
	// the concentrator on distinct addresses, set dest_addr per path.
	DestAddr netip.AddrPort `toml:"-"`
	// DestAddrRaw is the TOML string form of DestAddr; parsed in normalize.
	DestAddrRaw string `toml:"dest_addr"`
	// LinkBandwidthBitsPerSec is the OPERATOR-DECLARED bottleneck bandwidth of this
	// uplink in bits/s, parsed from LinkBandwidthRaw in normalize. It is used ONLY to
	// size the weighted scheduler's per-path pace from the bandwidth-delay product
	// (SizePacingFromBDP) when the weighted policy runs with pacing ENABLED (T53, Q20);
	// it is OPERATOR-DECLARED, not runtime-measured — wanbond never auto-tunes it live.
	// Zero means "not declared" (the synthetic default pace is kept).
	LinkBandwidthBitsPerSec float64 `toml:"-"`
	// LinkBandwidthRaw is the TOML string form of the declared bandwidth, e.g.
	// "50Mbit" / "1Gbit" / "500kbit" (SI bit/s units; the "bit" suffix may be written
	// "bps"). Parsed in normalize; a non-positive or unparseable value fails fast.
	LinkBandwidthRaw string `toml:"link_bandwidth"`
	// LinkRTT is the OPERATOR-DECLARED baseline RTT of this uplink, parsed from
	// LinkRTTRaw in normalize. It is the delay term of the bandwidth-delay-product pace
	// burst (one RTT of in-flight frames); required (> 0) when LinkBandwidth is set and
	// pacing is enabled under the weighted policy, ignored otherwise.
	LinkRTT time.Duration `toml:"-"`
	// LinkRTTRaw is the TOML Go-duration string form of LinkRTT, e.g. "45ms". Parsed in
	// normalize; an unparseable or non-positive value fails fast.
	LinkRTTRaw string `toml:"link_rtt"`
	// Bind selects this path's bind mode (I5, Q42): "source", "device", or "auto".
	// Left empty in TOML, it falls back to the top-level Config.Bind default (itself
	// defaulted to BindModeAuto); normalize() resolves this field to its EFFECTIVE
	// value, so after Load it always holds one of the three valid modes, never
	// empty. See BindMode.
	Bind BindMode `toml:"bind"`
}

// WireGuard holds the inner tunnel's key material.
type WireGuard struct {
	PrivateKey Key    `toml:"private_key"`
	Peers      []Peer `toml:"peers"`
	// ListenPort is the UDP port the concentrator listens on; 0 on the edge.
	ListenPort uint16 `toml:"listen_port"`
}

// PeerMode selects a peer's full-tunnel intent (I6, Q41 — thin surface):
// PeerModeDefaultRoute marks a peer as the edge's full-tunnel concentrator,
// permitting a 0.0.0.0/0 (and/or ::/0) entry in that peer's allowed_ips. The
// UAPI renderer (uapiConfig) ALWAYS splits a literal 0.0.0.0/0 or ::/0 into
// the equivalent /1+/1 pair regardless of mode (D35 — the engine wedges on
// the literal /0), so this field is a config-surface/validation concern only:
// it does not itself drive the split, and it does not yet wire any OS-level
// default-route/policy-routing behavior on the edge (that is a later task).
type PeerMode string

const (
	// PeerModeDefaultRoute marks this peer as the edge's full-tunnel
	// concentrator. Edge-only: a concentrator-role config declaring it on any
	// peer is a config error, mirroring the endpoint/dns edge-only rules.
	PeerModeDefaultRoute PeerMode = "default-route"
)

func (m PeerMode) valid() bool {
	return m == "" || m == PeerModeDefaultRoute
}

// Peer is one WireGuard peer.
type Peer struct {
	PublicKey Key `toml:"public_key"`
	// Endpoint is the peer's SINGLE tunnel address (edge -> concentrator); the
	// legacy single-endpoint config form, mutually exclusive with EndpointsRaw.
	// Empty on the concentrator, which roams the edge's endpoint dynamically.
	// A bare `endpoint = "..."` is normalized in resolveEndpoints to a one-
	// element Endpoints list, so it stays behavior-identical to the pre-T54
	// config surface.
	Endpoint string `toml:"endpoint"`
	// EndpointsRaw is the ORDERED list of concentrator (peer) endpoint address:port
	// strings for the edge-side hub-failover config surface (Q18): index 0 is the
	// active/primary concentrator, the rest are ordered standbys. Edge-only; a
	// concentrator declaring it is a config error (validate). Mutually exclusive
	// with the legacy Endpoint field.
	EndpointsRaw []string `toml:"endpoints"`
	// Endpoints is EndpointsRaw (or the single legacy Endpoint, as a one-element
	// list) parsed to netip.AddrPort and de-duplicated; populated by
	// resolveEndpoints in normalize(). This is the shape T57's hub-failover
	// switch consumes: Endpoints[0] is the active concentrator, Endpoints[1:]
	// are the ordered standbys to fail over to in order when all paths to the
	// active one are down. A hostname entry (Q35) contributes NO element here at
	// load time — resolution happens at runtime, not at config load (Q30) — so
	// Endpoints only ever holds the literal-address entries, in order.
	Endpoints []netip.AddrPort `toml:"-"`
	// DNS is the explicit per-peer opt-in (Q29) for hostname endpoint entries: a
	// hostname entry in endpoint/endpoints without dns = true is a config load
	// error naming this flag. Default-off, so an existing IP-literal config never
	// takes a new code path. Edge-only; a concentrator declaring dns = true is a
	// config error, mirroring the endpoints-not-meaningful-for-concentrator rule.
	DNS bool `toml:"dns"`
	// EndpointSpecs is the ordered, typed per-entry parse of the endpoint/
	// endpoints entries (Q35): each entry is either a literal address:port
	// (IsName=false, Addr set — parsed with EXACTLY today's netip.ParseAddrPort
	// path) or, when DNS opts in, a hostname:port (IsName=true, Host/Port set).
	// Populated by resolveEndpoints in normalize(); order matches the TOML list.
	EndpointSpecs []EndpointSpec `toml:"-"`
	// AllowedIPs are the CIDR ranges routed to this peer.
	AllowedIPs []string `toml:"allowed_ips"`
	// Mode is this peer's full-tunnel intent (I6, Q41): unset, or
	// "default-route" to mark it as the edge's full-tunnel concentrator. See
	// PeerMode.
	Mode PeerMode `toml:"mode"`
	// PSK is this peer's per-peer override of the outer-control PSK (G4
	// multi-peer concentrator groundwork). With a single configured peer it
	// must be left UNSET: the top-level Config.PSK remains the single-peer
	// default, so a legacy single-peer config carrying only the top-level
	// `psk` parses and behaves byte-identically to before this field existed.
	// With more than one peer, validate requires it to be present and
	// pairwise-distinct across peers (T81, Q21) — the top-level psk alone
	// cannot discriminate which peer authenticated an inbound frame, and equal
	// per-peer psks would defeat that authenticated demux. device.go calls
	// cfg.PeerIdentities() to derive each peer's effective PSK, and
	// bind/multipath.go consumes those per-peer PSKs for the peerBySource
	// PROBE-authenticated demux.
	PSK Key `toml:"psk"`
	// Name is this peer's human-readable identifier (G4 multi-peer
	// concentrator groundwork), analogous to Path.Name. Unused and optional
	// with a single peer; required and must be unique across peers when more
	// than one is configured (T81, Q21). Surfaces (for additional concentrator
	// peers) as the metrics 'peer' label via BoundPeerNames/PeerSnapshot.Name.
	Name string `toml:"name"`
}

// EndpointSpec is one parsed peer endpoint entry (Q35). A literal address:port
// entry parses via netip.ParseAddrPort and sets Addr (IsName=false); a
// hostname:port entry (accepted only when the owning Peer opts in with
// dns = true) sets Host/Port and IsName=true instead — no resolution happens at
// config load (Q30 defers it to runtime).
type EndpointSpec struct {
	// Host is the hostname, set only when IsName is true.
	Host string
	// Port is the port for a hostname entry, set only when IsName is true.
	Port uint16
	// Addr is the parsed literal address:port, set only when IsName is false.
	Addr netip.AddrPort
	// IsName reports whether this entry is a hostname (true) or an IP literal
	// (false).
	IsName bool
}

// resolveEndpoints canonicalizes the peer's endpoint config into the ordered
// Endpoints list (Q18) and the ordered, typed EndpointSpecs list (Q35): the
// legacy single Endpoint field and the new ordered EndpointsRaw list are
// mutually exclusive input forms, but a bare `endpoint = "..."` is normalized
// here to a ONE-ELEMENT list — so it stays behavior-identical to the pre-T54
// single-defaultRemote config surface. Each entry is tried FIRST as a literal
// netip.AddrPort ("host:port"), the same format bind.Multipath.ParseEndpoint
// requires of the UAPI endpoint string at runtime — an all-literal config
// takes EXACTLY this path, unchanged, with the same errors and the same
// duplicate detection as before T67 (Q29). Only when that parse fails, AND the
// host portion is not itself a malformed IP literal, is the entry split as
// host:port and treated as a hostname, gated behind the peer's explicit DNS
// opt-in (Q29); a hostname entry without the opt-in is a config error naming
// the flag. No resolution happens here (Q30 defers it to runtime). Duplicates
// are rejected within each of the two namespaces: a literal duplicating a
// literal, or a hostname:port duplicating another hostname:port.
func (p *Peer) resolveEndpoints() error {
	if p.Endpoint != "" && len(p.EndpointsRaw) > 0 {
		return errors.New("endpoint and endpoints are mutually exclusive; endpoint is the single-entry legacy form of endpoints")
	}
	raw := p.EndpointsRaw
	if p.Endpoint != "" {
		raw = []string{p.Endpoint}
	}
	seen := make(map[netip.AddrPort]struct{}, len(raw))
	seenNames := make(map[string]struct{}, len(raw))
	endpoints := make([]netip.AddrPort, 0, len(raw))
	specs := make([]EndpointSpec, 0, len(raw))
	for _, s := range raw {
		ap, err := netip.ParseAddrPort(s)
		if err == nil {
			if _, dup := seen[ap]; dup {
				return fmt.Errorf("duplicate endpoint %q", s)
			}
			seen[ap] = struct{}{}
			endpoints = append(endpoints, ap)
			specs = append(specs, EndpointSpec{Addr: ap})
			continue
		}
		host, portStr, splitErr := net.SplitHostPort(s)
		if splitErr != nil {
			return fmt.Errorf("invalid endpoint %q: %w", s, err)
		}
		// The host portion parses as an IP: this is a malformed IP-literal entry
		// (e.g. a bad port), not a hostname — report the ORIGINAL ParseAddrPort
		// error rather than diverting it into the hostname path, so every
		// IP-shaped entry keeps today's exact error.
		if _, ipErr := netip.ParseAddr(host); ipErr == nil {
			return fmt.Errorf("invalid endpoint %q: %w", s, err)
		}
		if !p.DNS {
			return fmt.Errorf("invalid endpoint %q: hostname endpoints require the peer's dns = true opt-in flag", s)
		}
		port, portErr := strconv.ParseUint(portStr, 10, 16)
		if portErr != nil || port == 0 {
			return fmt.Errorf("invalid endpoint %q: invalid port %q", s, portStr)
		}
		if hostErr := validateHostname(host); hostErr != nil {
			return fmt.Errorf("invalid endpoint %q: %w", s, hostErr)
		}
		nameKey := host + ":" + portStr
		if _, dup := seenNames[nameKey]; dup {
			return fmt.Errorf("duplicate endpoint %q", s)
		}
		seenNames[nameKey] = struct{}{}
		specs = append(specs, EndpointSpec{Host: host, Port: uint16(port), IsName: true})
	}
	p.Endpoints = endpoints
	p.EndpointSpecs = specs
	return nil
}

// validateHostname reports whether host is a syntactically valid DNS hostname
// (RFC 1123 label rules): 1-253 characters total, each dot-separated label
// 1-63 characters of letters/digits/hyphens, no leading or trailing hyphen.
func validateHostname(host string) error {
	if len(host) == 0 || len(host) > 253 {
		return fmt.Errorf("hostname %q must be 1-253 characters", host)
	}
	for _, label := range strings.Split(host, ".") {
		if len(label) == 0 || len(label) > 63 {
			return fmt.Errorf("hostname label %q must be 1-63 characters", label)
		}
		if label[0] == '-' || label[len(label)-1] == '-' {
			return fmt.Errorf("hostname label %q must not start or end with a hyphen", label)
		}
		for _, r := range label {
			alnum := (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9')
			if !alnum && r != '-' {
				return fmt.Errorf("hostname label %q contains invalid character %q", label, r)
			}
		}
	}
	return nil
}

// PeerIdentity is one configured WireGuard peer's effective outer-control PSK
// and stable name/id (G4 multi-peer concentrator groundwork).
type PeerIdentity struct {
	// PSK is this peer's effective outer-control PSK: for a single-peer config
	// it is the top-level Config.PSK (the pre-G4 back-compat default, unaffected
	// by any per-peer psk); for a multi-peer config it is the peer's own PSK
	// field. validate() rejects a per-peer psk when exactly one peer is
	// configured, so the single-peer-with-distinct-per-peer-psk shape is not
	// loadable via config.Load; this field still defends the invariant
	// defensively for any Config value built directly.
	PSK Key
	// Name is this peer's stable identifier: its configured Name when set,
	// otherwise a fallback derived from its public key (the first 8 bytes,
	// lowercase hex — the same short-key form uapiConfig uses to name a peer
	// in error messages), so every peer has a non-empty, stable id even when
	// name is omitted.
	Name string
}

// PeerIdentities returns, for each configured WireGuard peer in order, its
// effective PSK and stable name/id (G4). This is the SINGLE place the
// single-peer/multi-peer PSK back-compat decision is made: device.Up and the
// Bind consume PeerIdentities instead of each re-deriving the effective PSK
// from Config.PSK vs Peer.PSK. Order matches c.WireGuard.Peers.
func (c Config) PeerIdentities() []PeerIdentity {
	peers := c.WireGuard.Peers
	ids := make([]PeerIdentity, len(peers))
	for i, p := range peers {
		psk := p.PSK
		if len(peers) == 1 {
			// Single-peer back-compat: the top-level psk remains the effective
			// PSK regardless of whether a per-peer psk is also set.
			psk = c.PSK
		}
		name := p.Name
		if name == "" {
			pub := p.PublicKey.Bytes()
			name = hex.EncodeToString(pub[:8])
		}
		ids[i] = PeerIdentity{PSK: psk, Name: name}
	}
	return ids
}

// Amnezia holds the amneziawg-go obfuscation parameters. They must match on both
// ends for the handshake to succeed; they are defense-in-depth only.
//
// The block is "all-or-nothing": either every junk/size knob is left zero (plain
// WireGuard) or the whole obfuscation set (jc, jmin, jmax, s1, s2) is specified.
// A PARTIAL block silently produces an obfuscation profile the two ends cannot
// agree on, so validate rejects it at load (defect D1). The four magic headers
// (h1-h4) default to the standard message-type values 1..4 when omitted.
type Amnezia struct {
	Jc   int    `toml:"jc"`
	Jmin int    `toml:"jmin"`
	Jmax int    `toml:"jmax"`
	S1   int    `toml:"s1"`
	S2   int    `toml:"s2"`
	H1   uint32 `toml:"h1"`
	H2   uint32 `toml:"h2"`
	H3   uint32 `toml:"h3"`
	H4   uint32 `toml:"h4"`
}

// defaultMagicHeaders are the standard WireGuard message-type headers: initiation,
// response, cookie-reply, and transport. amneziawg-go treats any magic header <= 4
// as "use the standard type", so 1..4 is the canonical "headers not obfuscated"
// profile. wanbond emits them explicitly (rather than 0) so a configured amnezia
// block always carries a complete, self-consistent set of magic headers.
var defaultMagicHeaders = [4]uint32{1, 2, 3, 4}

// Configured reports whether the amnezia block carries any obfuscation parameter.
// An all-zero block leaves the engine in plain WireGuard mode.
func (a Amnezia) Configured() bool {
	return a.Jc != 0 || a.Jmin != 0 || a.Jmax != 0 || a.S1 != 0 || a.S2 != 0 ||
		a.H1 != 0 || a.H2 != 0 || a.H3 != 0 || a.H4 != 0
}

// applyDefaults fills in the standard magic headers (1..4) when the block is
// configured but no header was given, so the UAPI renderer emits an explicit,
// complete header set instead of h1=0..h4=0. It is a no-op for an unconfigured
// block and for one that already sets any header (a partial header set is left
// intact so validate can reject it).
func (a *Amnezia) applyDefaults() {
	if !a.Configured() {
		return
	}
	if a.H1 == 0 && a.H2 == 0 && a.H3 == 0 && a.H4 == 0 {
		a.H1, a.H2, a.H3, a.H4 = defaultMagicHeaders[0], defaultMagicHeaders[1], defaultMagicHeaders[2], defaultMagicHeaders[3]
	}
}

// Metrics configures the localhost Prometheus endpoint.
type Metrics struct {
	// Listen is the address the /metrics endpoint binds to; must be loopback.
	Listen string `toml:"listen"`
}

// Log configures structured logging.
type Log struct {
	Level string `toml:"level"`
