1324	// validate enforces the amnezia obfuscation invariants (defect D1). An
1325	// unconfigured block is valid (plain WireGuard). A configured block must specify
1326	// the WHOLE junk/size set and carry a consistent magic-header set, so a partial
1327	// or inconsistent obfuscation profile FAILS FAST at load rather than producing a
1328	// silently mismatched tunnel that never handshakes.
1329	//
1330	// This runs after applyDefaults, so an omitted magic-header set has already been
1331	// filled with the standard 1..4 values; the header check below therefore only
1332	// fires for a genuinely partial header set (some given, some left zero).
1333	func (a Amnezia) validate() error {
1334		if !a.Configured() {
1335			return nil
1336		}
1337		// All-or-nothing: enabling amnezia at all requires the full junk/size set, so
1338		// both ends are forced to specify the same complete profile. A partial block
1339		// (e.g. jc/jmin/jmax set but s1/s2 omitted) would leave the ends deriving
1340		// different profiles and the handshake would fail closed with no diagnostic.
1341		if a.Jc <= 0 || a.Jmin <= 0 || a.Jmax <= 0 || a.S1 <= 0 || a.S2 <= 0 {
1342			return fmt.Errorf("amnezia: incomplete obfuscation set — when configured, jc, jmin, jmax, s1 and s2 must all be > 0 (got jc=%d jmin=%d jmax=%d s1=%d s2=%d)",
1343				a.Jc, a.Jmin, a.Jmax, a.S1, a.S2)
1344		}
1345		if a.Jmin > a.Jmax {
1346			return fmt.Errorf("amnezia: require jmin <= jmax, got jmin=%d jmax=%d", a.Jmin, a.Jmax)
1347		}
1348		// Junk sizes must not collide: amneziawg-go classifies an incoming datagram's
1349		// message type by its on-the-wire length, so the obfuscated initiation packet
1350		// (MessageInitiationSize + s1) and response packet (MessageResponseSize + s2)
1351		// must differ in length. A colliding s1/s2 pair passes config load but is
1352		// rejected later by the engine's IpcSet ("new init size == new response size");
1353		// reject it here so the collision fails fast at load, at the right locus. The
1354		// engine's own MessageInitiationSize (148) and MessageResponseSize (92)
1355		// constants are used so this check tracks the vendored fork if it ever changes.
1356		if awgdevice.MessageInitiationSize+a.S1 == awgdevice.MessageResponseSize+a.S2 {
1357			return fmt.Errorf("amnezia: junk sizes collide — obfuscated init size %d (%d+s1) must differ from response size %d (%d+s2); adjust s1/s2",
1358				awgdevice.MessageInitiationSize+a.S1, awgdevice.MessageInitiationSize,
1359				awgdevice.MessageResponseSize+a.S2, awgdevice.MessageResponseSize)
1360		}
1361		// Magic headers must be distinct: the receive path classifies a datagram's
1362		// message type by its header value, so two equal headers make two message
1363		// types indistinguishable. An all-zero header set is left for applyDefaults;
1364		// any non-zero header requires a complete, distinct set (a partial set leaves
1365		// zeros here and is caught as a duplicate).
1366		if a.H1 != 0 || a.H2 != 0 || a.H3 != 0 || a.H4 != 0 {
1367			if a.H1 == a.H2 || a.H1 == a.H3 || a.H1 == a.H4 ||
1368				a.H2 == a.H3 || a.H2 == a.H4 || a.H3 == a.H4 {
1369				return fmt.Errorf("amnezia: magic headers must be a complete, distinct set, got h1=%d h2=%d h3=%d h4=%d",
1370					a.H1, a.H2, a.H3, a.H4)
1371			}
1372		}
1373		return nil
1374	}
